SELECT [CFG Variant Detail].*
FROM [CFG Variant Detail]
WHERE ((([CFG Variant Detail].[Model Item No_])="7FARIA01/LEA" Or ([CFG Variant Detail].[Model Item No_])="7FWOSUONO01/LEA" Or ([CFG Variant Detail].[Model Item No_])="YLE14/TEXTURED" Or ([CFG Variant Detail].[Model Item No_])="DLY32/NET" Or ([CFG Variant Detail].[Model Item No_])="JNE04/CROSTA-VIT" Or ([CFG Variant Detail].[Model Item No_])="7FMURRAY01/LEA" Or ([CFG Variant Detail].[Model Item No_])="7SWOBOWLING/LEA" Or ([CFG Variant Detail].[Model Item No_])="8SMADISON01/MES" Or ([CFG Variant Detail].[Model Item No_])="8SMASTER01/LEA"));

